mapper.select:


    AND r.user_id = #{userId}
    AND r.venue_id = #{venueId}
    AND r.spot_id = #{spotId}
    AND r.status = #{status}
    AND r.reserve_date >= #{params.beginTime}
    AND r.reserve_date <= #{params.endTime}

order by r.reserve_date desc, r.create_time desc


where r.spot_id = #{spotId} and r.reserve_date = #{reserveDate}
and r.time_slot = #{timeSlot} and r.status in (0, 1)
limit 1
